#!/usr/bin/env python3
"""install_heatmap_v3.py — BatKnock heatmap with zone editor
Run from ~/Desktop/BatKnock:  python3 install_heatmap_v3.py
"""
import base64, os, sys
if not os.path.isdir("screens"): sys.exit("Run from BatKnock root")
PAYLOAD = ""
with open("screens/HeatmapScreen.js", "wb") as f:
    f.write(base64.b64decode(PAYLOAD))
print("✅ screens/HeatmapScreen.js updated")
print()
print("Now run:  npx expo start --clear --lan")
print()
print("How to use the zone editor:")
print("  1. Go to Bat Profile → View Heatmap")
print("  2. Tap '✏️ Edit Zone Boundaries'")
print("  3. Drag the 3 coloured lines to match your bat photo:")
print("     — Blue line  = where the blade starts (below handle)")
print("     — Amber line = where the sweet spot begins")
print("     — Red line   = where the toe begins")
print("  4. Tap 'Save Zone Boundaries'")
print("  5. The heatmap overlay will now align exactly with your bat")
